import java.util.*;

class Ogrenci implements Comparable<Ogrenci> {
    String ad; int yas;
    Ogrenci(String ad, int yas) { this.ad = ad; this.yas = yas; }
    public int compareTo(Ogrenci o) { return Integer.compare(this.yas, o.yas); }
    public String toString() { return ad + "-" + yas; }
}
List<Ogrenci> liste = Arrays.asList(new Ogrenci("Ali", 25), new Ogrenci("Ayse", 20));
Collections.sort(liste);
System.out.println(liste);
